    private RszTools() {
    }

    public static RekenBasisRszKey bijdrageToBasis(MoneyKey bijdrageKey) {
        return BIJDRAGE_BASIS.get(bijdrageKey);
    }

    public static boolean komtInAanmerkingBijzondereBijdrage(Hoedanigheid hoedanigheid, CategorieKengetal categorieKengetal, RekenTijd rekenTijd) {
        boolean komtInAanmerking = KOMT_IN_AANMERKING_BIJZONDERE_BIJDRAGE.contains(hoedanigheid);
        return komtInAanmerking && !uitTeSluitenStudentenEnMonitoren(categorieKengetal, rekenTijd);
    }

    private static boolean uitTeSluitenStudentenEnMonitoren(CategorieKengetal categorieKengetal, RekenTijd rekenTijd) {
        if (RekenTools.getTijdperk(rekenTijd) == AkeTijdperk.DMFAPPL && !rekenTijd.beginDatum.isBefore(UITSLUITENS_STUDENTEN_EN_MONITOREN)) {
            return categorieKengetal.isStudentOfMonitorMetBijzondereCategorie();
        } else {
            return false;
        }
    }

    public static boolean isVervallenWerknemersKengetal(DmfapplWnkengetal werknemersKengetal, LocalDate zoekDatum) {
        LocalDate aanpassing = WNKKENGETAL_TO_VERVAL_DATUM.get(werknemersKengetal);
        return aanpassing != null && aanpassing.isBefore(zoekDatum);
    }

    public static LocalDate zoekDatumAanpassenVoorVervallenWnkKengetallen(DmfapplWnkengetal werknemersKengetal, LocalDate zoekDatum) {
        if (isVervallenWerknemersKengetal(werknemersKengetal, zoekDatum)) {
            return WNKKENGETAL_TO_VERVAL_DATUM.get(werknemersKengetal);
        } else {
            return zoekDatum;
        }
    }

    public static boolean heeftBasisRsz(AardKodeExtensie loonCode) {
        return loonCode.getCode() < MIN_LOONCODE_ZONDER_BASIS_RSZ || loonCode.getCode() == LOONCODE_CORONAPREMIE;
    }
